import React, { useState, useEffect } from 'react';

const TestScenarios: React.FC = () => {
  const [scenarios, setScenarios] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    const fetchScenarios = async () => {
      try {
        setLoading(true);
        const response = await fetch('http://localhost:5000/api/scenarios');
        const data = await response.json();
        
        if (data.success) {
          setScenarios(data.data);
        } else {
          setError('Failed to fetch scenarios: ' + data.message);
        }
      } catch (err) {
        setError('Error fetching scenarios: ' + (err as Error).message);
      } finally {
        setLoading(false);
      }
    };

    fetchScenarios();
  }, []);

  if (loading) {
    return <div>Loading...</div>;
  }

  if (error) {
    return <div>Error: {error}</div>;
  }

  return (
    <div>
      <h1>Test Scenarios</h1>
      <p>Number of scenarios: {scenarios.length}</p>
      <pre>{JSON.stringify(scenarios, null, 2)}</pre>
    </div>
  );
};

export default TestScenarios;
